<?php namespace App\Domains\Construction\Policies; use Illuminate\Auth\Access\HandlesAuthorization; class ProjectPolicy { use HandlesAuthorization; public function viewAny($user) { return true; } public function view($user, $project) { return $user->tenant_id === $project->tenant_id; } public function create($user) { return true; } public function update($user, $project) { return $user->tenant_id === $project->tenant_id; } public function delete($user, $project) { return $user->tenant_id === $project->tenant_id; } }
